// Flutter imports:
import 'package:flutter/material.dart';

// Package imports:
import 'package:flutter_hooks/flutter_hooks.dart';

// Project imports:
import 'package:baseball_detector_flutter/constants.dart';
import 'package:baseball_detector_flutter/controllers/locale_controller.dart';
import 'package:baseball_detector_flutter/utils/locale_ext.dart';
import 'package:baseball_detector_flutter/utils/web_url.dart';
import 'package:baseball_detector_flutter/views/hooks/use_widget_ref.dart';

/// チュートリアルの YouTube 動画を開くカスタムフック
/// isForRecording == true の場合は、チュートリアル動画の撮影の説明部分を開始位置に指定した URL を開く
VoidCallback useTutorialVideo({bool isForRecording = false}) {
  final ref = useWidgetRef();
  final isJapanese = ref.watch(localeControllerProvider).isJapanese;

  return useCallback(() {
    final url = isForRecording
        ? isJapanese
            ? Constants.recordingExplanationVideoURLJa
            : Constants.recordingExplanationVideoURLEn
        : isJapanese
            ? Constants.howToUseSmartScoutURLJa
            : Constants.howToUseSmartScoutURLEn;
    openURLWithSystemBrowser(url: url);
  }, [isJapanese]);
}

